 72→          maxFontSizeMultiplier={1.2}
 73→          mb="quark"
 74→        >
 75→          {label}
 76→        </Text>
 77→      )}
 78→
 79→      <Content
 80→        testID="DS-InputBox-Content"
 81→        width={width}
 82→        error={error}
 83→        active={value}
 84→        editable={editable}
