105→            }
106→          }}
107→          editable={editable}
108→          subtitle={subtitle}
109→          onPressIn={() => editable && onPressIn?.()}
110→          placeholderTextColor={
111→            error ? colors.DENY_COLOR_01 : colors.INTENSE_COLOR_03
112→          }
113→          placeholder={placeholder}
114→          selectionColor={colors.EMPHASIS_COLOR_01}
115→          secureTextEntry={secureTextEntry}
116→          error={error}
