146→              }
147→              onPressIcon?.();
148→            }}
149→          />
150→        )}
151→
152→        {!!textRight && (
153→          <Text
154→            ml="nano"
155→            maxFontSizeMultiplier={1.2}
156→            type="linkSM"
157→            color="BRAND_BASE_01"
158→            onPress={onPressTextRight}
159→            disabled={disableOnPressTextRight}
160→            testID="DS-InputBox-textRight"
161→          >
162→            {textRight}
163→          </Text>
164→        )}
165→
166→        {isLoading && <LoadingCore ml="nano" />}
167→      </Content>
168→
169→      {showSecondLabel &&
170→      (componentRef?.current?.isFocused() ||
171→        inputRef?.current?.isFocused() ||
172→        value ||
173→        !editable) ? (
174→        <Text
175→          testID="DS-InputBox-SecondLabel"
176→          mt="quark"
177→          maxFontSizeMultiplier={1.2}
178→          type="paragraphSM"
179→          color="INTENSE_COLOR_05"
180→        >
181→          {secondLabelText}
182→        </Text>
183→      ) : null}
184→
185→      {hasError && (
186→        <Text
187→          testID="DS-InputBox-textError"
188→          mt="quark"
189→          maxFontSizeMultiplier={1.2}
190→          type="paragraphSM"
191→          color="DENY_COLOR_01"
192→        >
193→          {textError}
194→        </Text>
195→      )}
196→    </Box>
197→  );
198→}
