 10→
 11→function Icon({
 12→  testID,
 13→  mb,
 14→  ml,
 15→  mr,
 16→  mt,
 17→  size,
 18→  name,
 19→  style,
 20→  color,
 21→  onPress,
 22→  iconSet,
 23→  disabled = !onPress,
 24→  hasBackground = false,
 25→  hasBackgroundCircle = false,
 26→  backgroundType = 'square',
 27→  bgColor = 'LIGHT_BASE_03',
 28→  bgColorCircle,
 29→  borderColor = 'INTENSE_COLOR_02',
 30→  hasStroke = false,
 31→  shadow = 'none',
 32→  hasBackgroundSvg = false,
 33→}: PropsIcon) {
 34→  const [isImage, setImage] = useState(false);
 35→  const showBackground =
 36→    size === 'xxs' ||
 37→    size === 'sx' ||
 38→    size === 'xs' ||
 39→    size === 'sm' ||
 40→    size === 'xm' ||
 41→    size === 'md' ||
 42→    size === 'gt';
 43→
 44→  const showBackgroundCircle =
 45→    size === 'xxs' ||
 46→    size === 'sx' ||
 47→    size === 'xs' ||
 48→    size === 'sm' ||
 49→    size === 'xm' ||
 50→    size === 'md' ||
 51→    size === 'gt';
 52→
 53→  const verifyIcon = () => {
 54→    let hasIcon = false;
 55→
 56→    icomoonSet.icons.forEach((item) => {
 57→      if (item.properties.name === name) {
 58→        hasIcon = true;
 59→      }
 60→    });
 61→
 62→    return hasIcon;
 63→  };
 64→
 65→  const sourceImage = (): ImageSourcePropType => {
 66→    if (name) {
 67→      return Object.prototype.hasOwnProperty.call(iconSelected, name)
 68→        ? iconSelected[name]
 69→        : iconSelected.undefined;
 70→    }
 71→    return [];
 72→  };
 73→
 74→  const verifyImage = useCallback(() => {
 75→    if (Object.prototype.hasOwnProperty.call(iconSelected, name)) {
 76→      return setImage(true);
 77→    }
 78→    return setImage(false);
 79→  }, [name]);
 80→
 81→  const bgPadding = (): PropsPaddingCore => {
 82→    if (hasBackground) {
 83→      if (size === 'xxs') {
 84→        return 'innerSmall';
 85→      }
 86→      if (size === 'sx') {
 87→        return 'innerSmall';
 88→      }
 89→      if (size === 'xs' || size === 'xm') {
 90→        return 'innerMiddle';
 91→      }
 92→      if (size === 'sm') {
 93→        return 'innerMedium';
 94→      }
 95→      if (size === 'md') {
 96→        return 'innerGreat';
 97→      }
 98→      if (size === 'gt') {
 99→        return 'innerGreat';
100→      }
101→    }
102→    return 'none';
103→  };
104→  const bgPaddingCircle = (): PropsPaddingCore => {
105→    if (
106→      hasBackgroundSvg &&
107→      hasBackground &&
108→      backgroundType === 'circle' &&
109→      size === 'gt'
110→    )
111→      return 'none';
112→
113→    if (hasBackground && hasBackgroundCircle && backgroundType === 'circle') {
114→      if (size === 'xxs' || size === 'sx') {
115→        return 'innerSmall';
116→      }
117→      if (size === 'xs' || size === 'xm') {
118→        return 'innerMiddle';
119→      }
120→      if (size === 'sm') {
121→        return 'innerMedium';
122→      }
123→      if (size === 'md' || size === 'gt') {
124→        return 'innerLarge';
125→      }
126→    }
127→    return 'none';
128→  };
129→
130→  const renderBgColor = () => {
131→    if (
132→      hasBackgroundSvg &&
133→      hasBackground &&
134→      backgroundType === 'circle' &&
135→      size === 'gt'
136→    )
137→      return 'transparent';
138→
139→    if (
140→      hasBackground &&
141→      hasBackgroundCircle &&
142→      backgroundType === 'circle' &&
143→      showBackgroundCircle
144→    )
145→      return bgColorCircle;
146→
147→    return 'transparent';
148→  };
149→
150→  useEffect(() => {
151→    verifyImage();
152→  }, [verifyImage]);
153→
154→  return (
155→    <View
156→      size={size}
157→      name={name}
158→      style={style}
159→      color={color}
160→      onPress={onPress}
161→      iconSet={iconSet}
162→      testID={testID}
163→      disabled={disabled}
164→      mb={mb}
165→      ml={ml}
166→      mr={mr}
167→      mt={mt}
168→      verifyIcon={verifyIcon}
169→      sourceImage={sourceImage}
170→      isImage={isImage}
171→      bgPadding={bgPadding}
172→      backgroundType={backgroundType}
173→      bgColor={bgColor}
174→      hasStroke={hasStroke}
175→      borderColor={borderColor}
176→      hasBackground={hasBackground}
177→      showBackground={showBackground}
178→      shadow={shadow}
179→      bgPaddingCircle={bgPaddingCircle}
180→      showBackgroundCircle={showBackgroundCircle}
181→      hasBackgroundCircle={hasBackgroundCircle}
182→      bgColorCircle={bgColorCircle}
183→      hasBackgroundSvg={hasBackgroundSvg}
184→      renderBgColor={renderBgColor}
185→    />
186→  );
187→}
188→
189→export default Icon;
